<?php
require_once __DIR__ . '/library.php';

function sf_search_static_index(): array { global $catalogSongs,$videoCatalog,$episodes,$musicAlbum,$products; $rows=[]; foreach($catalogSongs as $s){$rows[]=['content_type'=>'song','content_id'=>(int)($s['id']??0),'title'=>$s['title']??'','slug'=>$s['slug']??'','description'=>($s['episode']??'').' '.($s['artist']??''),'image_path'=>$s['cover']??'images/music/soundtrack-cover.png','content_url'=>sf_library_content_url('song',(string)($s['slug']??'')),'access_level'=>$s['access']??'subscriber','weight'=>80];} foreach($videoCatalog as $v){$rows[]=['content_type'=>'video','content_id'=>(int)($v['id']??0),'title'=>$v['title']??'','slug'=>$v['slug']??'','description'=>$v['description']??'','image_path'=>$v['poster']??'images/episodes/episode-01.png','content_url'=>sf_library_content_url('video',(string)($v['slug']??'')),'access_level'=>$v['access_level']??'subscriber','weight'=>90];} foreach($episodes as $i=>$e){$rows[]=['content_type'=>'episode','content_id'=>$i+1,'title'=>$e['title']??'','slug'=>$e['slug']??'','description'=>$e['description']??'','image_path'=>$e['image']??'images/episodes/episode-01.png','content_url'=>sf_library_content_url('episode',(string)($e['slug']??'')),'access_level'=>'subscriber','weight'=>75];} if(!empty($musicAlbum)){$rows[]=['content_type'=>'album','content_id'=>1,'title'=>$musicAlbum['title']??'','slug'=>$musicAlbum['slug']??'','description'=>$musicAlbum['description']??'','image_path'=>$musicAlbum['cover']??'images/music/soundtrack-cover.png','content_url'=>sf_library_content_url('album',(string)($musicAlbum['slug']??'')),'access_level'=>'subscriber','weight'=>70];} foreach($products as $p){$rows[]=['content_type'=>'product','content_id'=>(int)($p['id']??0),'title'=>$p['name']??'','slug'=>$p['slug']??'','description'=>$p['description']??'','image_path'=>$p['image']??'images/merch/merch-hero.png','content_url'=>sf_library_content_url('product',(string)($p['slug']??'')),'access_level'=>'public','weight'=>55];} return $rows; }
function sf_search_db_rows(string $query='', string $type=''): array { $pdo=sf_db(); if(!$pdo||!sf_library_table_exists('content_search_index'))return []; try{$where="WHERE status='published'";$params=[]; if($query!==''){$where.=' AND (title LIKE ? OR description LIKE ? OR keywords LIKE ?)';$like='%'.$query.'%';$params=[$like,$like,$like];} if($type!==''){$where.=' AND content_type=?';$params[]=$type;} $s=$pdo->prepare("SELECT * FROM content_search_index {$where} ORDER BY is_featured DESC, weight DESC, updated_at DESC LIMIT 100"); $s->execute($params); return $s->fetchAll()?:[];}catch(Throwable $e){return [];} }
function sf_search_results(string $query='', string $type=''): array { $query=trim($query); $type=trim($type); $rows=sf_search_db_rows($query,$type); if(!$rows){$rows=sf_search_static_index(); if($type!=='')$rows=array_values(array_filter($rows,fn($r)=>($r['content_type']??'')===$type)); if($query!==''){$needle=strtolower($query);$rows=array_values(array_filter($rows,function($r)use($needle){return str_contains(strtolower(($r['title']??'').' '.($r['description']??'').' '.($r['slug']??'')),$needle);}));}} usort($rows,fn($a,$b)=>(int)($b['weight']??0)<=>(int)($a['weight']??0)); return $rows; }
function sf_search_facets(array $rows): array { $facets=[]; foreach($rows as $row){$type=(string)($row['content_type']??'other');$facets[$type]=($facets[$type]??0)+1;} return $facets; }
?>
